(function () {
  var EX = {
    linear: { name: 'Tìm kiếm tuyến tính', code: 'for i = 0..n-1:\n  if A[i] == x: return i\nreturn -1', loops: ['Một vòng lặp chạy tối đa n lần.', 'Mỗi lần có 1 phép so sánh A[i] == x.'], t: 'T(n) = n·1 + 1', o: 'O(n)', why: 'Khi n tăng gấp đôi, số so sánh xấu nhất cũng tăng gần gấp đôi.' },
    binary: { name: 'Tìm kiếm nhị phân', code: 'while left <= right:\n  mid = floor((left+right)/2)\n  compare A[mid] with x\n  keep half interval', loops: ['Mỗi vòng bỏ đi một nửa mảng.', 'Số vòng là số lần chia n cho 2 đến khi còn 1.'], t: 'T(n) = ⌈log₂ n⌉·c', o: 'O(log n)', why: 'Dữ liệu đã sắp xếp cho phép thu nhỏ không gian tìm kiếm theo lũy thừa 2.' },
    bubble: { name: 'Bubble sort', code: 'for i = 0..n-2:\n  for j = 0..n-i-2:\n    if A[j] > A[j+1]: swap', loops: ['Hai vòng lặp lồng nhau.', 'Số so sánh: (n-1)+(n-2)+...+1.'], t: 'T(n) = n(n-1)/2 + swap ≤ c·n²', o: 'O(n²)', why: 'Vòng lặp lồng nhau tạo số bước bậc hai khi n lớn.' },
    insertion: { name: 'Insertion sort', code: 'for i = 1..n-1:\n  key = A[i]\n  while j >= 0 and A[j] > key:\n    shift A[j]', loops: ['Vòng ngoài chạy n-1 lần.', 'Vòng while có thể lùi qua toàn bộ phần đã sắp.'], t: 'T(n) = 1+2+...+(n-1)', o: 'O(n²)', why: 'Trường hợp xấu nhất là mảng giảm dần; mỗi phần tử phải dịch qua nhiều vị trí.' }
  };
  function addStyle() { if (document.getElementById('aca-style')) return; var s = document.createElement('style'); s.id = 'aca-style'; s.textContent = '.aca-wrap{border:1px solid #e5e7eb;border-radius:12px;padding:16px;background:#fff;margin:14px 0}.aca-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(240px,1fr));gap:12px}.aca-card{padding:12px;border-radius:10px;background:#f8fafc;border:1px solid #e5e7eb}.aca-code{white-space:pre-wrap;background:#111827;color:#f9fafb;border-radius:8px;padding:12px;overflow:auto}.aca-big{font-size:1.5em;color:#007bff;font-weight:700}.aca-pill{display:inline-block;padding:4px 8px;border-radius:999px;background:#e8f4fd;border:1px solid #bfdbfe;margin:3px}.aca-select{padding:8px;border:1px solid #cbd5e1;border-radius:8px;margin-bottom:12px}'; document.head.appendChild(s); }
  function mount(host) { if (!host || host.dataset.acaMounted) return; host.dataset.acaMounted = '1'; addStyle(); host.innerHTML = '<div class="aca-wrap"><h4>🔬 Bộ phân tích độ phức tạp</h4><select class="aca-select" data-kind></select><div class="aca-grid"><div class="aca-card"><strong>Mã giả</strong><pre class="aca-code"></pre></div><div class="aca-card"><strong>Phân tích vòng lặp</strong><div class="aca-loops"></div></div><div class="aca-card"><strong>Suy ra T(n)</strong><p class="aca-t"></p><div class="aca-big"></div><p class="aca-why"></p></div></div></div>'; var sel = host.querySelector('[data-kind]'); Object.keys(EX).forEach(function (k) { sel.innerHTML += '<option value="' + k + '">' + EX[k].name + '</option>'; }); function paint() { var x = EX[sel.value]; host.querySelector('.aca-code').textContent = x.code; host.querySelector('.aca-loops').innerHTML = x.loops.map(function (l) { return '<span class="aca-pill">' + l + '</span>'; }).join(''); host.querySelector('.aca-t').textContent = x.t; host.querySelector('.aca-big').textContent = 'O(T(n)) = ' + x.o; host.querySelector('.aca-why').textContent = x.why; } sel.addEventListener('change', paint); paint(); }
  document.addEventListener('DOMContentLoaded', function () { document.querySelectorAll('[data-demo="algorithm-complexity-analyzer"]').forEach(mount); });
}());
